#include <stdio.h>
#include <stdlib.h>
int compare(const void *a, const void *b) { return (*(int*)a - *(int*)b); }
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N;
        scanf("%d", &N);
        int arr[N];
        for (int i = 0; i < N; i++) {
            scanf("%d", &arr[i]);
        }
        qsort(arr, N, sizeof(int), compare);
        int median = arr[N / 2];
        int sum = 0;
        for (int i = 0; i < N; i++) {
            sum += abs(arr[i] - median);
        }
        printf("%d\n", sum);
    }
    return 0;
}

