const readline = require('readline').createInterface({
    input: process.stdin,
    output: process.stdout
});
let i = 0;
let T;
let input = [];
readline.on('line', line => {
    if (i === 0) {
        T = parseInt(line);
    } else {
        input.push(line);
    }
    i++;
    if (i === T * 2 + 1) {
        for (let j = 0; j < T; j++) {
            let N = parseInt(input[j * 2]);
            let arr = input[j * 2 + 1].split(' ').map(x => parseInt(x));
            arr.sort((a, b) => a - b);
            let median = arr[Math.floor(N / 2)];
            let sum = 0;
            for (let k = 0; k < N; k++) {
                sum += Math.abs(arr[k] - median);
            }
            console.log(sum);
        }
    }
});
